require_once __DIR__.'/functions.php';if($_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(405);exit;}verify_csrf();$member=require_member();$postId=filter_input(INPUT_POST,'post_id',FILTER_VALIDATE_INT);$content=trim((string)($_POST['contenido']??''));if(!$postId||$content===''||mb_strlen($content)>3000){flash('Escribe un comentario válido.','error');redirect('/');}$stmt=db()->prepare('SELECT slug FROM posts WHERE id=?');$stmt->execute([$postId]);$slug=$stmt->fetchColumn();if(!$slug){http_response_code(404);exit('Artículo no encontrado.');}db()->prepare('INSERT INTO comments(post_id,member_id,nombre,email,contenido) VALUES(?,?,?,?,?)')->execute([$postId,$member['id'],$member['display_name'],$member['email'],$content]);flash('Comentario recibido. Aparecerá cuando sea aprobado.');redirect('/'.rawurlencode((string)$slug));
